    @Test fun `butterworthBandpassFiltFilt matches scipy reference within 1e-6`() {
        val actual = DspPrimitives.butterworthBandpassFiltFilt(filtfiltInput)
        assertEquals("length must match", filtfiltExpected.size, actual.size)
        for (i in actual.indices) {
            assertEquals("sample $i", filtfiltExpected[i], actual[i], 1e-6)
        }
    }

